LOCATIONS = ['Ahmedabad', 'Bangalore', 'Chennai', 'Delhi', 'Hyderabad', 'Jaipur', 'Kochi', 'Kolkata', 'Mumbai', 'Pune']
FUEL_TYPES = ['Petrol', 'Diesel', 'CNG', 'LPG', 'Electric']
TRANSMISSIONS = ['Manual', 'Automatic']
OWNER_TYPES = ['First', 'Second', 'Third', 'Fourth & Above']
SEATS = [2, 4, 5, 6, 7, 8, 9, 10]

def home(request):
    return render(request, 'home.html')

@login_required
def predict_view(request):
    ctx = {
        'brands': sorted(BRAND_MODELS.keys()),
        'locations': LOCATIONS,
        'fuel_types': FUEL_TYPES,
        'transmissions': TRANSMISSIONS,
        'owner_types': OWNER_TYPES,
        'seats': SEATS,
        'years': list(range(2019, 1997, -1)),
        'brand_models_json': json.dumps(BRAND_MODELS),
        'avg_stats_json': json.dumps(AVG_STATS),
    }
    return render(request, 'predictor/predict.html', ctx)

@login_required
def predict_result(request):
    if request.method != 'POST':
        return redirect('predict')
    try:
        brand = request.POST.get('brand')
        model_name = request.POST.get('model')
        location = request.POST.get('location')
        year = int(request.POST.get('year'))
        km = int(request.POST.get('kilometers_driven'))
        fuel = request.POST.get('fuel_type')
        transmission = request.POST.get('transmission')
        owner = request.POST.get('owner_type')
        mileage = float(request.POST.get('mileage'))
        engine = float(request.POST.get('engine'))
        power = float(request.POST.get('power'))
        seats = float(request.POST.get('seats'))

        input_df = pd.DataFrame([{
            'Location': location,
            'Year': year,
            'Kilometers_Driven': km,
            'Fuel_Type': fuel,
            'Transmission': transmission,
            'Owner_Type': owner,
            'Mileage': mileage,
            'Engine': engine,
            'Power': power,
            'Seats': seats,
            'Brand': brand,
            'Model': model_name,
        }])

        prediction = MODEL.predict(input_df)[0]
        # Model was trained on log(price) — apply exp() to get real price
        price_lakh = round(exp(float(prediction)), 2)
        # Convert to USD (1 Lakh INR = 100,000 INR, 1 INR ≈ 0.012 USD)
        price_usd = round(price_lakh * 100000 * 0.012)

        # Dynamic confidence: based on how complete/typical the input is
        # More recent year + lower km + first owner = higher confidence
        base = 72
        if year >= 2015: base += 8
        elif year >= 2010: base += 4
        if km < 50000: base += 6
        elif km < 100000: base += 3
        if owner == 'First': base += 5
        elif owner == 'Second': base += 2
        if fuel in ['Petrol', 'Diesel']: base += 4
        confidence = min(base, 95)

        ctx = {
            'price': price_lakh,
            'price_usd': f"{price_usd:,}",
            'brand': brand,
            'model': model_name,
            'year': year,
            'location': location,
            'fuel': fuel,
            'transmission': transmission,
            'owner': owner,
            'km': f"{km:,}",
            'confidence': confidence,
        }
        return render(request, 'predictor/result.html', ctx)
    except Exception as e:
        return render(request, 'predictor/predict.html', {
            'error': str(e),
            'brands': sorted(BRAND_MODELS.keys()),
            'locations': LOCATIONS,
            'fuel_types': FUEL_TYPES,
            'transmissions': TRANSMISSIONS,
            'owner_types': OWNER_TYPES,
            'seats': SEATS,
            'years': list(range(2019, 1997, -1)),
            'brand_models_json': json.dumps(BRAND_MODELS),
            'avg_stats_json': json.dumps(AVG_STATS),
        })

def get_models_api(request):
    brand = request.GET.get('brand', '')
    models = BRAND_MODELS.get(brand, [])
    return JsonResponse({'models': models})
